boot.artifact:
// inferred-not-tested:artifact 列 H0 探针未闭合
import { Molecule } from 'https://cdn.jsdelivr.net/npm/openchemlib@9/+esm';
const el = document.getElementById('molecule'); el.style.height = '320px';
const mol = data.format === 'molfile' ? Molecule.fromMolfile(data.source) : Molecule.fromSmiles(data.source);
el.innerHTML = mol.toSVG(el.clientWidth || 480, 320); // SVG 仅来自上游描绘器

boot.widget:
// 纯 JS 解析;生成 SVG 落到 shadow 容器
import { Molecule } from 'https://cdn.jsdelivr.net/npm/openchemlib@9/+esm';
const el = document.createElement('div'); el.style.height = '320px'; shadowRoot.appendChild(el);
const mol = data.format === 'molfile' ? Molecule.fromMolfile(data.source) : Molecule.fromSmiles(data.source);
el.innerHTML = mol.toSVG(el.clientWidth || 480, 320);
